# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def multi_step_checkout(cart_items, discount_code, user, payment_method):
    # Step 1: Validate cart items
    def validate_cart_items(items):
        if not items:
            raise ValueError("Cart is empty")
        for item in items:
            if item.get('quantity', 0) <= 0:
                raise ValueError("Invalid quantity in cart")
            if item.get('price', 0) < 0:
                raise ValueError("Invalid price in cart")
        return sum(item.get('price', 0) * item.get('quantity', 0) for item in items)
    
    # Step 2: Apply discount codes
    def apply_discount(total, code, user):
        if not code:
            return total, 0
        
        valid_codes = {
            'SAVE10': {'discount': 0.1, 'admin_only': False, 'tier': 'all'},
            'SAVE20': {'discount': 0.2, 'admin_only': False, 'tier': 'premium'},
            'SAVE30': {'discount': 0.3, 'admin_only': True, 'tier': 'all'},
            'WELCOME': {'discount': 0.15, 'admin_only': False, 'tier': 'new'}
        }
        
        if code not in valid_codes:
            raise ValueError("Invalid discount code")
        
        code_info = valid_codes[code]
        
        if code_info['admin_only'] and not user.get('is_admin', False):
            raise ValueError("Admin-only discount code")
        
        if code_info['tier'] != 'all' and code_info['tier'] != user.get('tier', 'basic'):
            raise ValueError("Insufficient user tier for discount code")
        
        discount_amount = total * code_info['discount']
        return total - discount_amount, discount_amount
    
    # Step 3: Calculate tax
    def calculate_tax(total):
        tax_rate = 0.08
        return total * tax_rate
    
    # Step 4: Process payment
    def process_payment(total, payment_method):
        if not payment_method:
            raise ValueError("Payment method is required")
        
        if total <= 0:
            raise ValueError("Invalid payment amount")
        
        # Simulate payment processing
        return {"status": "success", "amount": total, "method": payment_method}
    
    # Step 5: Create order record
    def create_order_record(items, discount_amount, tax_amount, payment_info, user):
        order = {
            "items": items,
            "subtotal": sum(item.get('price', 0) * item.get('quantity', 0) for item in items),
            "discount_amount": discount_amount,
            "tax_amount": tax_amount,
            "total_amount": sum(item.get('price', 0) * item.get('quantity', 0) for item in items) - discount_amount + tax_amount,
            "payment_info": payment_info,
            "user_id": user.get('id'),
            "status": "completed"
        }
        return order
    
    try:
        # Execute steps sequentially
        subtotal = validate_cart_items(cart_items)
        discounted_total, discount_amount = apply_discount(subtotal, discount_code, user)
        tax_amount = calculate_tax(discounted_total)
        payment_info = process_payment(discounted_total + tax_amount, payment_method)
        order_record = create_order_record(cart_items, discount_amount, tax_amount, payment_info, user)
        
        return order_record
    except Exception as e:
        raise e